REQUIRED = {'case_id', 'created', 'method', 'resource', 'status'}
REJECT = 'RETURN_CORRECT_HTTP_STATUS'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (record["status"] == 200 and record["method"] == "GET")
    return "PASS" if contract_ok else REJECT

